import{_ as a,o as e,c as n,ag as l}from"./chunks/framework.DXGyWiRo.js";const D=JSON.parse('{"title":"PostgreSQL Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guides/postgresql.md","filePath":"guides/postgresql.md"}'),t={name:"guides/postgresql.md"};function o(p,s,c,i,r,d){return e(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="postgresql-guide" tabindex="-1">PostgreSQL Guide <a class="header-anchor" href="#postgresql-guide" aria-label="Permalink to &quot;PostgreSQL Guide&quot;">​</a></h1><p><code>PGClient</code> is the direct PostgreSQL client for LinkedQL. It gives you full SQL access, transactions, and realtime capabilities over a native PostgreSQL connection.</p><p>Use <code>PGClient</code> when your application talks directly to PostgreSQL.</p><blockquote><p><code>PGClient</code> uses the <code>node-postgres</code> connector under the hood and accepts all the existing constructor options.</p></blockquote><hr><h2 id="setup" tabindex="-1">Setup <a class="header-anchor" href="#setup" aria-label="Permalink to &quot;Setup&quot;">​</a></h2><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> PGClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  port</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 5432</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mydb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  poolMode</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> false</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">SELECT 1::text AS result</span><span style="color:#89DDFF;">&#39;</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#BABED8;">console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#BABED8;">(result</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">rows)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// [{ result: &#39;1&#39; }]</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">disconnect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="connection-mode" tabindex="-1">Connection Mode <a class="header-anchor" href="#connection-mode" aria-label="Permalink to &quot;Connection Mode&quot;">​</a></h2><p>By default, <code>PGClient</code> runs on a single PostgreSQL connection.</p><p>You can opt into connection pooling by enabling <code>poolMode</code>:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  port</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 5432</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">mydb</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  poolMode</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>In <code>poolMode</code>, <code>PGClient</code> uses a connection pool to handle concurrent queries more efficiently.</p><p>After initializing the instance via <code>db.connect()</code>, subsequent <code>db.connect()</code> calls simply return a checked-out client.</p><p>This lets you explicitly check out a connection for session-sensitive work:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> client </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// ... run session-bound queries</span></span>
<span class="line"><span style="color:#BABED8;">client</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">release</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is useful for transactions or workflows that require a stable connection.</p><hr><h2 id="realtime-setup" tabindex="-1">Realtime Setup <a class="header-anchor" href="#realtime-setup" aria-label="Permalink to &quot;Realtime Setup&quot;">​</a></h2><p>LinkedQL uses PostgreSQL&#39;s logical replication to power <a href="/realtime/live-queries">live queries</a> and <a href="/api/wal-subscribe"><code>db.wal.subscribe()</code></a>. This requires logical replication to be enabled on the PostgreSQL instance.</p><p>At minimum, set in your database config file:</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>wal_level = logical</span></span></code></pre></div><p>Depending on your setup, you may also need:</p><div class="language-conf"><button title="Copy Code" class="copy"></button><span class="lang">conf</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span>max_replication_slots = 10</span></span>
<span class="line"><span>max_wal_senders = 10</span></span></code></pre></div><p>Refer to the <a href="https://www.postgresql.org/docs/current/logical-replication-config.html" target="_blank" rel="noreferrer">official PostgreSQL documentation</a> for enabling logical replication.</p><blockquote><p>Restart PostgreSQL after changing these settings.</p></blockquote><p>Once enabled, LinkedQL handles the rest automatically:</p><ul><li>creates a replication slot if it does not already exist</li><li>creates a publication if it does not already exist</li><li>subscribes to and decodes the WAL stream</li></ul><p>The replication slot name and publication name that LinkedQL uses by default are:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Setting</th><th style="text-align:left;">Default</th></tr></thead><tbody><tr><td style="text-align:left;">Replication slot</td><td style="text-align:left;"><code>linkedql_default_slot</code> (ephemeral by default)</td></tr><tr><td style="text-align:left;">Publication</td><td style="text-align:left;"><code>linkedql_default_publication</code></td></tr></tbody></table><p>Note that by default, when LinkedQL creates a publication, it creates it for all tables.</p><p>You can override these defaults if needed via constructor options:</p><table tabindex="0"><thead><tr><th style="text-align:left;">Option</th><th style="text-align:left;">Type</th><th style="text-align:left;">Default</th><th style="text-align:left;">Meaning</th></tr></thead><tbody><tr><td style="text-align:left;"><code>walSlotName</code></td><td style="text-align:left;"><code>string</code></td><td style="text-align:left;"><code>&#39;linkedql_default_slot&#39;</code></td><td style="text-align:left;">logical replication slot name</td></tr><tr><td style="text-align:left;"><code>walSlotPersistence</code></td><td style="text-align:left;"><code>0 | 1</code></td><td style="text-align:left;"><code>0</code></td><td style="text-align:left;">whether the slot should be ephemeral or persistent</td></tr><tr><td style="text-align:left;"><code>pgPublications</code></td><td style="text-align:left;"><code>string | string[]</code></td><td style="text-align:left;"><code>&#39;linkedql_default_publication&#39;</code></td><td style="text-align:left;">publication(s) used for change streaming</td></tr></tbody></table><p>Example:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  walSlotName</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">my_slot</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  walSlotPersistence</span><span style="color:#89DDFF;">:</span><span style="color:#F78C6C;"> 1</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  pgPublications</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">my_publication</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>This is useful when:</p><ul><li>you manage replication slots manually</li><li>you need persistent slots</li><li>you want to integrate with an existing replication setup</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>LinkedQL consumes PostgreSQL&#39;s WAL using the <code>pgoutput</code> plugin, the same mechanism PostgreSQL uses for native logical replication.</p></div><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">the common application-facing methods</td><td style="text-align:left;"><a href="/api">API</a></td></tr><tr><td style="text-align:left;">how this fits into larger app architectures</td><td style="text-align:left;"><a href="/guides/integration-patterns">Integration Patterns</a></td></tr></tbody></table>`,41)])])}const F=a(t,[["render",o]]);export{D as __pageData,F as default};
